import collections

class GraphNode(object):
  def __init__(self,val):
    self.val = val
    self.edges = set()

class Solution(object):
  def __init__(self):
    self.root = None

  def construct(self,A):
    #dfs takes a valid node, and populates its children by going thru edges
    #dfs calls itself on this node's children after it populates the children
    #dfs returns the node
    def dfs(node):
      for below_node in self.below[node]:
        self.above[below_node].discard(node)
        if len(self.above[below_node]) == 0:
          node.edges.add(below_node)
      for e in node.edges:
        dfs(e)
      return node

    self.below = collections.defaultdict(set)
    self.above = collections.defaultdict(set)
    self.graph = {}

    for a,b in A:
      if a not in self.graph:
        self.graph[a] = GraphNode(a)
      if b not in self.graph:
        self.graph[b] = GraphNode(b)

      self.below[self.graph[a]].add(self.graph[b])
      self.above[self.graph[b]].add(self.graph[a])

    [#find](https://leetcode.com/problems/find-first-and-last-position-of-element-in-sorted-array) root
    for k,v in self.graph.items():
      if len(self.below[v]) == len(self.graph) - 1:
        self.root = v
    [#call](https://leetcode.com/problems/read-n-characters-given-read4-ii-call-multiple-times) dfs on root
    return dfs(self.root)

  def display(self):
    def dfs(node):
      print('node',node.val)
      for e in node.edges:
        print('...children',e.val)
      for e in node.edges:
        dfs(e)
    dfs(self.root)

